import{_ as e,o as i,c as o,ae as t}from"./chunks/framework.D_vkKrCz.js";const s=JSON.parse('{"title":"应用案例库","description":"","frontmatter":{"sidebar":true},"headers":[],"relativePath":"cases.md","filePath":"cases.md"}'),r={name:"cases.md"};function h(l,a,u,d,n,c){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="应用案例库" tabindex="-1">应用案例库 <a class="header-anchor" href="#应用案例库" aria-label="Permalink to &quot;应用案例库&quot;">​</a></h1><p>IM2ODE经过十年技术积累，已在多个材料设计领域取得成功应用，部分已得到实验验证的典型案例如下：</p><hr><h2 id="半导体材料设计" tabindex="-1">半导体材料设计 <a class="header-anchor" href="#半导体材料设计" aria-label="Permalink to &quot;半导体材料设计&quot;">​</a></h2><h3 id="低带隙tio2相预测" tabindex="-1">低带隙TiO₂相预测 <a class="header-anchor" href="#低带隙tio2相预测" aria-label="Permalink to &quot;低带隙TiO₂相预测&quot;">​</a></h3><p>通过多目标全局优化方法，成功预测了多种具有低带隙的新型TiO₂相，有望应用于光催化和太阳能电池领域。 <em>相关论文：Chen HZ, Zhang YY, Gong XG</em>, Xiang HJ*, &quot;Predicting New TiO₂ Phases with Low Band Gaps by a Multiobjective Global Optimization Approach&quot;, J. PHYS. Chem. C, 2014, 118, 2333-2337.*</p><blockquote><p>📋 <a href="/im2ode.github.io/guide/configuration.html#tio₂多目标带隙优化">参考配置</a> | 🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#多目标优化参数">Multi-Objective</a> | <a href="/im2ode.github.io/guide/configuration.html#多目标优化参数">ESflag</a></p></blockquote><hr><h2 id="低维纳米材料设计" tabindex="-1">低维纳米材料设计 <a class="header-anchor" href="#低维纳米材料设计" aria-label="Permalink to &quot;低维纳米材料设计&quot;">​</a></h2><h3 id="高居里温度二维铁磁cr-i材料" tabindex="-1">高居里温度二维铁磁Cr-I材料 <a class="header-anchor" href="#高居里温度二维铁磁cr-i材料" aria-label="Permalink to &quot;高居里温度二维铁磁Cr-I材料&quot;">​</a></h3><p>成功预测多种具有高居里温度的二维Cr-I铁磁材料，其中最高Tc可达592K，为二维自旋电子器件应用提供了候选材料，相关成果发表于《Chinese Physics Letters》。</p><blockquote><p>📋 <a href="/im2ode.github.io/guide/configuration.html#fese准二维材料搜索">参考配置</a> | 🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#准二维材料参数">Q2D</a> | <a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">fix_lat</a></p></blockquote><h3 id="二维nacl半金属" tabindex="-1">二维NaCl半金属 <a class="header-anchor" href="#二维nacl半金属" aria-label="Permalink to &quot;二维NaCl半金属&quot;">​</a></h3><p>理论预测新型二维NaCl半金属结构，并得到实验合成验证，突破了传统块体材料的性能限制，相关成果发表于《Nature Communications》。</p><blockquote><p>🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#准二维材料参数">Q2D</a> | <a href="/im2ode.github.io/guide/configuration.html#多目标优化参数">Multi-Objective</a></p></blockquote><h3 id="二维vcl纳米板超顺磁材料" tabindex="-1">二维VCl纳米板超顺磁材料 <a class="header-anchor" href="#二维vcl纳米板超顺磁材料" aria-label="Permalink to &quot;二维VCl纳米板超顺磁材料&quot;">​</a></h3><p>设计并合成具有超顺磁特性的二维VCl纳米板材料，在自旋电子器件和磁存储领域具有重要应用价值，相关成果发表于《Nano Letters》。</p><blockquote><p>🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">cluster</a> | <a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">model_surface</a></p></blockquote><hr><h2 id="超硬材料设计" tabindex="-1">超硬材料设计 <a class="header-anchor" href="#超硬材料设计" aria-label="Permalink to &quot;超硬材料设计&quot;">​</a></h2><h3 id="新型超硬碳结构设计" tabindex="-1">新型超硬碳结构设计 <a class="header-anchor" href="#新型超硬碳结构设计" aria-label="Permalink to &quot;新型超硬碳结构设计&quot;">​</a></h3><p>设计了多种新型sp³杂化的碳同素异形体，硬度接近金刚石，同时具有优异的电学性能。</p><blockquote><p>🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#多目标优化参数">Hardness</a> | <a href="/im2ode.github.io/guide/configuration.html#基础参数说明">Symmetry</a></p></blockquote><hr><h2 id="表面-界面-缺陷-晶界设计" tabindex="-1">表面/界面/缺陷/晶界设计 <a class="header-anchor" href="#表面-界面-缺陷-晶界设计" aria-label="Permalink to &quot;表面/界面/缺陷/晶界设计&quot;">​</a></h2><h3 id="pd-ceo2表面重构设计" tabindex="-1">Pd-CeO₂表面重构设计 <a class="header-anchor" href="#pd-ceo2表面重构设计" aria-label="Permalink to &quot;Pd-CeO₂表面重构设计&quot;">​</a></h3><p>针对不同温度和氧分压条件，精准预测Pd-CeO₂催化剂的表面重构结构，为催化剂性能优化提供理论指导，相关成果发表于《Physical Review Letters》。</p><blockquote><p>📋 <a href="/im2ode.github.io/guide/configuration.html#tio₂表面结构搜索">参考配置</a> | 🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">model_surface</a> | <a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">cluster_substrate</a></p></blockquote><h3 id="晶界结构优化" tabindex="-1">晶界结构优化 <a class="header-anchor" href="#晶界结构优化" aria-label="Permalink to &quot;晶界结构优化&quot;">​</a></h3><p>针对SrTiO₃等氧化物晶界结构进行全局优化，得到低能晶界原子构型，解释晶界电输运性能调控机制。</p><blockquote><p>📋 <a href="/im2ode.github.io/guide/configuration.html#晶界结构搜索">参考配置</a> | 🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">model_gb</a></p></blockquote><h3 id="点缺陷结构搜索" tabindex="-1">点缺陷结构搜索 <a class="header-anchor" href="#点缺陷结构搜索" aria-label="Permalink to &quot;点缺陷结构搜索&quot;">​</a></h3><p>精准预测氧化物中点缺陷的稳定构型及电子结构，为缺陷工程调控材料性能提供理论指导。</p><blockquote><p>🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">find_defect</a></p></blockquote><hr><h2 id="团簇结构设计" tabindex="-1">团簇结构设计 <a class="header-anchor" href="#团簇结构设计" aria-label="Permalink to &quot;团簇结构设计&quot;">​</a></h2><h3 id="pdau合金团簇" tabindex="-1">PdAu合金团簇 <a class="header-anchor" href="#pdau合金团簇" aria-label="Permalink to &quot;PdAu合金团簇&quot;">​</a></h3><p>预测PdAu合金团簇的稳定结构，解释其催化性能与团簇尺寸、组分的依赖关系。</p><blockquote><p>📋 <a href="/im2ode.github.io/guide/configuration.html#pdau团簇搜索">参考配置</a> | 🔑 核心参数：<a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">cluster</a> | <a href="/im2ode.github.io/guide/configuration.html#团簇衬底缺陷表面晶界参数">model_ball</a></p></blockquote><hr><h2 id="更多应用领域" tabindex="-1">更多应用领域 <a class="header-anchor" href="#更多应用领域" aria-label="Permalink to &quot;更多应用领域&quot;">​</a></h2><p>IM2ODE已被国内外多个研究团队广泛应用于：</p><ul><li>✅ 锂离子电池电极材料设计</li><li>✅ 热电材料设计</li><li>✅ 催化材料设计</li><li>✅ 拓扑材料设计</li><li>✅ 储氢材料设计</li><li>✅ 铁电功能材料设计</li><li>✅ 低维纳米材料设计</li></ul><p>如果你有使用IM2ODE发表的工作，欢迎联系我们添加到案例展示中！</p>',44)])])}const m=e(r,[["render",h]]);export{s as __pageData,m as default};
